   fs.writeFileSync(usgPath, JSON.stringify(usages, null, 4));


   if (!command) {
     var allCommandName = [];
     const commandValues = commands['keys']();

     const tdung = require('./../../img/gaivip.json');
     var image1 = tdung[Math.floor(Math.random() * tdung.length)].trim();
