function buildAPI(globalOptions, html, jar, bypass_region) {
    //new feat
    const fb_dtsg = utils.getFroms(html, '["DTSGInitData",[],{"token":"', '","')[0]; //nhăm nhăm nhăm nhăm

    //check tiktik
