const { existsSync, writeFileSync, mkdirSync } = global.nodemodule["fs-extra"];
const { join } = global.nodemodule["path"];
const moment = require("moment-timezone");

module.exports.config = {
    name: "autosetname",
    version: "1.0.1",
    hasPermssion: 1,
    credits: "Vtuan (Modified by AI)",
    description: "Tự động setname cho thành viên mới",
    commandCategory: "Quản Lí Box",
    usages: "[add <name> /remove]",
    cooldowns: 0
};

module.exports.onLoad = () => {
    const pathCache = join(__dirname, "data");
    const pathData = join(pathCache, "autosetname.json");

    if (!existsSync(pathCache)) mkdirSync(pathCache, { recursive: true });
    if (!existsSync(pathData)) writeFileSync(pathData, "[]", "utf-8");
};

module.exports.run = async function ({ event, api, args }) {
    const { threadID, messageID } = event;
    const { readFileSync, writeFileSync } = global.nodemodule["fs-extra"];
    const pathData = join(__dirname, "data","autosetname.json");

    let dataJson;
    try {
        dataJson = JSON.parse(readFileSync(pathData, "utf-8"));
    } catch (error) {
        dataJson = [];
        writeFileSync(pathData, JSON.stringify([]), "utf-8");
    }

    const thisThread = dataJson.find(item => item.threadID == threadID) || { threadID, nameUser: [] };

    const content = args.slice(1).join(" ");
    switch (args[0]) {
        case "add":
            if (!content) return api.sendMessage("→ Bạn chưa nhập cấu hình tên!", threadID, messageID);
            if (thisThread.nameUser.length > 0) return api.sendMessage("→ Cấu hình cũ tồn tại! Vui lòng xóa cấu hình trước.", threadID, messageID);

            thisThread.nameUser.push(content);
            if (!dataJson.some(item => item.threadID == threadID)) dataJson.push(thisThread);
            writeFileSync(pathData, JSON.stringify(dataJson, null, 4), "utf-8");
            return api.sendMessage(`→ Đặt cấu hình tên thành viên mới thành công: ${content}`, threadID, messageID);

        case "remove":
            if (thisThread.nameUser.length === 0) return api.sendMessage("→ Không có cấu hình để xóa!", threadID, messageID);

            thisThread.nameUser = [];
            const index = dataJson.findIndex(item => item.threadID == threadID);
            if (index !== -1) dataJson.splice(index, 1);
            writeFileSync(pathData, JSON.stringify(dataJson, null, 4), "utf-8");
            return api.sendMessage("→ Xóa cấu hình thành công!", threadID, messageID);

        default:
            return api.sendMessage(
                `hướng dẫn sử dụng:
#autosetname add biệt danh: biệt danh tạm thời cho thành viên mới
#autosetname remove: bỏ tự đặt biệt danh cho thành viên mới
`,
                threadID,
                messageID
            );
    }
};

modules/commands/avt.js.content:
const fs = require('fs');
const axios = require('axios');

module.exports.config = {
    name: "avt",
    version: "1.0.0",
    hasPermssion: 0,
    credits: "Jukie",
    description: "Lấy ảnh đại diện",
    commandCategory: "Công cụ",
    usages: "[user|box|tid]",
    cooldowns: 3
};

module.exports.run = async ({ api, event, args, Users }) => {
    const { threadID, messageID, senderID, type, messageReply, mentions } = event;

    const sendImage = async (url, message) => {
        try {
            const response = await axios.get(url, { responseType: 'arraybuffer' });
            if (response.status !== 200) {
                return api.sendMessage("⚠️ Không thể tải ảnh đại diện. Vui lòng thử lại sau.", threadID, messageID);
            }
            const imagePath = __dirname + '/cache/avt.png';
            fs.writeFileSync(imagePath, response.data);
            api.sendMessage({ body: message, attachment: fs.createReadStream(imagePath) }, threadID, () => {
                fs.unlinkSync(imagePath);
            }, messageID);
        } catch (error) {
            console.error(error);
            api.sendMessage("⚠️ Đã có lỗi xảy ra, vui lòng thử lại sau.", threadID, messageID);
        }
    };

    if (args.length === 0) {
        return api.sendMessage(`⚡️Bạn có thể dùng:\n\n${this.config.name} user => nó sẽ lấy ảnh đại diện của chính bạn.\n\n${this.config.name} user @[Tag] => nó sẽ lấy ảnh đại diện của người bạn tag.\n\n${this.config.name} box => nó sẽ lấy ảnh đại diện của box của bạn\n\n${this.config.name} user box tid => nó sẽ lấy ảnh đại diện của tid`, threadID, messageID);
    }

    if (args[0] === "box") {
        let targetThreadID = threadID;
        if (args[1]) targetThreadID = args[1];

        try {
            const threadInfo = await api.getThreadInfo(targetThreadID);
            if (!threadInfo.imageSrc) {
                return api.sendMessage(`⚡️Box này không có ảnh đại diện`, threadID, messageID);
            }
            return sendImage(threadInfo.imageSrc, `⚡️Ảnh đại diện của box ${threadInfo.threadName} đây`);
        } catch (error) {
            console.error(error);
            return api.sendMessage("⚠️ Không thể lấy thông tin của box. Vui lòng thử lại sau.", threadID, messageID);
        }
    }

    if (args[0] === "user") {
        let targetID = senderID;

        if (args[1]) {
            if (Object.keys(mentions).length > 0) {
                targetID = Object.keys(mentions)[0];
            } else if (args[1] === "tid") {
                if (args[2]) {
                    targetID = args[2];
                } else {
                    return api.sendMessage(`⚡️Bạn chưa nhập ID của người dùng`, threadID, messageID);
                }
            }
        } else if (type === "message_reply") {
            targetID = messageReply.senderID;
        }

        try {
            const userInfo = await Users.getData(targetID);
            const userName = userInfo.name || "người dùng";
            const imageUrl = `https://graph.facebook.com/${targetID}/picture?height=720&width=720&access_token=6628568379|c1e620fa708a1d5696fb991c1bde5662`;
            return sendImage(imageUrl, `⚡️Ảnh đại diện của ${userName} đây`);
        } catch (error) {
            console.error(error);
