          uidUser = handleReply.uidUser[num - 1];

          api.unfriend(uidUser);
          msg += '- ' + name + '\n🌐ProfileUrl: ' + urlUser + "\n";
          //console.log(msg);
        }

        api.sendMessage(`💢Thực thi xoá bạn bè💢\n\n${msg}`, threadID, () =>
          api.unsendMessage(handleReply.messageID));
