      }
      global.moduleData.werewolf = new Map();
      return api.sendMessage('➜ Tổng Ngày Trôi Qua: ' + Days + '\x0aTổng Người Còn Sống: ' + All['length'] + '\x0a\x0a' + Objection,event.threadID);
