const axios = require("axios");
const fs = require("fs-extra");
const FormData = require("form-data");

module.exports.config = {
  name: "upanh",
  version: "1.3.0",
  hasPermssion: 0,
  credits: "ChatGPT",
  description: "Upload ảnh/video lên Cloudinary (unsigned) + fallback Postimages",
  commandCategory: "Công cụ",
  usages: "[reply ảnh hoặc video]",
  cooldowns: 5
};

module.exports.run = async ({ api, event }) => {
  const { threadID, type, messageReply, messageID } = event;

  // ---- Cấu hình Cloudinary unsigned ----
  // Thay bằng thông tin của bạn hoặc set vào biến môi trường
  const CLOUD_NAME = process.env.CLOUDINARY_CLOUD_NAME || "YOUR_CLOUD_NAME";
  const UPLOAD_PRESET = process.env.CLOUDINARY_UPLOAD_PRESET || "YOUR_UNSIGNED_PRESET";
  // ---------------------------------------

  if (CLOUD_NAME === "YOUR_CLOUD_NAME" || UPLOAD_PRESET === "YOUR_UNSIGNED_PRESET") {
    console.warn("Chú ý: Bạn chưa cấu hình CLOUD_NAME / UPLOAD_PRESET. Sẽ cố fallback sang Postimages nếu Cloudinary không hoạt động.");
  }

  if (type !== "message_reply" || !messageReply?.attachments?.length) {
    return api.sendMessage("⚠️ Hãy reply vào **1 ảnh hoặc video** để upload!", threadID, messageID);
  }

  const links = [];

  for (const att of messageReply.attachments) {
    const t = att.type;
    if (!["photo", "animated_image", "video"].includes(t)) {
      // skip các loại không hỗ trợ
      continue;
    }

    const ext = (t === "photo") ? "jpg" : (t === "video") ? "mp4" : "gif";
    const tmpPath = __dirname + `/cache/${Date.now()}.${ext}`;

    try {
      // tải file tạm
      const res = await axios.get(att.url, { responseType: "arraybuffer", timeout: 30_000 });
      await fs.writeFile(tmpPath, res.data);

      let uploadedLink = null;

      // --- Try Cloudinary unsigned upload (image or video endpoint) ---
      if (CLOUD_NAME && UPLOAD_PRESET && CLOUD_NAME !== "YOUR_CLOUD_NAME" && UPLOAD_PRESET !== "YOUR_UNSIGNED_PRESET") {
        try {
          const form = new FormData();
          form.append("file", fs.createReadStream(tmpPath));
          form.append("upload_preset", UPLOAD_PRESET);

          // chọn endpoint theo loại media
          const resourceType = (t === "video") ? "video" : "image";
          const url = `https://api.cloudinary.com/v1_1/${CLOUD_NAME}/${resourceType}/upload`;

          const resp = await axios.post(url, form, { headers: form.getHeaders(), timeout: 60_000 });
          if (resp?.data?.secure_url) {
            uploadedLink = resp.data.secure_url; // direct link
          } else if (resp?.data?.url) {
            uploadedLink = resp.data.url;
          }
        } catch (err) {
          console.log("⚠️ Cloudinary upload lỗi:", err.message || err.toString());
        }
      }

      // --- Nếu Cloudinary fail -> fallback Postimages (chỉ cho ảnh/gif; Postimages không hỗ trợ video lớn) ---
      if (!uploadedLink) {
        try {
          // Postimages chủ yếu cho ảnh/gif. Nếu là video bạn có thể dùng khác (ví dụ: Publitio) — ở đây vẫn thử Postimages.
          const form2 = new FormData();
          form2.append("file", fs.createReadStream(tmpPath));
          form2.append("format", "json");

          const r2 = await axios.post("https://api.postimages.org/1/upload", form2, { headers: form2.getHeaders(), timeout: 60_000 });
          if (r2?.data?.data?.direct_link) {
            uploadedLink = r2.data.data.direct_link;
          } else if (r2?.data?.data?.url) {
            uploadedLink = r2.data.data.url;
          }
        } catch (err) {
          console.log("⚠️ Postimages upload lỗi:", err.message || err.toString());
        }
      }

      // Xóa file tạm
      if (fs.existsSync(tmpPath)) await fs.unlink(tmpPath);

      if (uploadedLink) links.push(uploadedLink);
      else links.push("❌ Upload thất bại!"); // tuỳ bạn có muốn push dòng lỗi này hay skip
    } catch (err) {
      console.error("❌ Lỗi khi xử lý file:", err.message || err.toString());
      if (fs.existsSync(tmpPath)) await fs.unlink(tmpPath);
      links.push("❌ Upload thất bại!");
    }
  }

  const good = links.filter(l => l && !l.includes("❌"));
  if (good.length === 0) return api.sendMessage("❌ Upload thất bại hoàn toàn!", threadID, messageID);

  // Trả **chỉ** link trực tiếp (mỗi link một dòng)
  return api.sendMessage(good.join("\n"), threadID, messageID);
};

