      .then((resData) => {
        if (utils.getType(resData) != "Array") {
          if (okeoke.request.uri && okeoke.request.uri.href.includes("https://www.facebook.com/checkpoint/")) {
            if (okeoke.request.uri.href.includes('601051028565049')) {
