  8: "female_plural",
  9: "male_plural",
  10: "neuter_plural",
  11: "unknown_plural"
};

function formatData(obj) {
  return Object.keys(obj).map(function (key) {
    var user = obj[key];
    return {
      alternateName: user.alternateName,
      firstName: user.firstName,
      gender: GENDERS[user.gender],
