              else if (!isNaN(Link.split('=')[1]) && Link.split('=')[1]) {
                var Format = `https://www.facebook.com/profile.php?id=${Link.split('=')[1]}`;
                FindUID(Format,api).then(function (data) {
                  callback(null, data);
                });
              } 
              else {
                FindUID(Link,api).then(function (data) {
                  callback(null, data);
                });
